/**
 * Adds a dark mask over the entire world except Italy.
 * Uses the inverted polygon technique: world rectangle with
 * Italy's real borders cut out as holes.
 */
function addItalyMask(map) {
  // Outer ring: covers the entire world
  var world = [
    [-90, -180], [-90, 180], [90, 180], [90, -180], [-90, -180]
  ];

  // Build the polygon rings: world outer, then Italy shapes as holes
  var rings = [world, ITALY_BORDERS.mainland, ITALY_BORDERS.sicily, ITALY_BORDERS.sardinia, ITALY_BORDERS.elba];

  // Dark overlay with Italy cut out
  L.polygon(rings, {
    color: 'none',
    weight: 0,
    fillColor: '#1a1a2e',
    fillOpacity: 0.35,
    interactive: false,
    smoothFactor: 1
  }).addTo(map);

  // Subtle border around Italy
  var borderRings = [ITALY_BORDERS.mainland, ITALY_BORDERS.sicily, ITALY_BORDERS.sardinia, ITALY_BORDERS.elba];
  L.polygon(borderRings, {
    color: '#008C45',
    weight: 1.5,
    opacity: 0.25,
    fill: false,
    interactive: false,
    smoothFactor: 1
  }).addTo(map);
}
